insert into public.composers (id, slug, name, name_cn, birth_year, death_year, country, period, portrait_url, short_bio, bio, style_tags, timeline, starter_work_ids, related_composer_ids, featured) values
  ('bach', 'bach', 'Johann Sebastian Bach', '约翰·塞巴斯蒂安·巴赫', 1685, 1750, '德国', '巴洛克', '', '巴洛克复调艺术的集大成者，以严谨结构和深沉精神性影响了后世所有作曲家。', '巴赫把德国管风琴传统、意大利协奏曲语汇和法国舞曲风格融为一体。他的音乐既是精密的结构，也是富有呼吸感的祈祷，从键盘、宗教声乐到室内乐都留下了典范。', '["复调","管风琴","宗教声乐","结构感"]'::jsonb, '[{"year":1708,"event":"任魏玛宫廷管风琴师。"},{"year":1721,"event":"完成《勃兰登堡协奏曲》献呈本。"},{"year":1723,"event":"赴莱比锡任圣托马斯教堂乐长。"}]'::jsonb, '["bach-cello-suite-1","bach-brandenburg-3","bach-goldberg"]'::jsonb, '["handel","mozart","beethoven"]'::jsonb, true),
  ('handel', 'handel', 'George Frideric Handel', '乔治·弗里德里希·亨德尔', 1685, 1759, '德国 / 英国', '巴洛克', '', '以歌剧和清唱剧闻名的巴洛克巨匠，音乐兼具戏剧性、宏阔感与公共庆典气质。', '亨德尔在德国出生，长期活跃于伦敦。他用意大利歌剧训练出的戏剧嗅觉，塑造了英语清唱剧的辉煌传统，《弥赛亚》成为音乐会舞台上最持久的作品之一。', '["清唱剧","歌剧","戏剧性","庆典感"]'::jsonb, '[{"year":1711,"event":"歌剧《里纳尔多》在伦敦成功上演。"},{"year":1742,"event":"《弥赛亚》在都柏林首演。"},{"year":1749,"event":"创作《皇家烟火音乐》。"}]'::jsonb, '["handel-messiah","handel-water-music","handel-fireworks"]'::jsonb, '["bach","haydn","mozart"]'::jsonb, false),
  ('mozart', 'mozart', 'Wolfgang Amadeus Mozart', '沃尔夫冈·阿马德乌斯·莫扎特', 1756, 1791, '奥地利', '古典主义', '', '古典主义均衡与歌唱性的象征，在歌剧、交响曲、协奏曲和室内乐中都达到罕见高度。', '莫扎特的音乐常以轻盈外表承载复杂情感。他让旋律像人声一样自然呼吸，也让戏剧人物拥有真实心理，古典风格在他笔下呈现出透明而深邃的光泽。', '["歌唱性","歌剧","透明织体","古典均衡"]'::jsonb, '[{"year":1762,"event":"幼年随父亲巡演欧洲宫廷。"},{"year":1781,"event":"离开萨尔茨堡，定居维也纳。"},{"year":1787,"event":"《唐璜》在布拉格首演。"}]'::jsonb, '["mozart-symphony-40","mozart-piano-concerto-21","mozart-requiem"]'::jsonb, '["haydn","beethoven","schubert"]'::jsonb, true),
  ('haydn', 'haydn', 'Joseph Haydn', '约瑟夫·海顿', 1732, 1809, '奥地利', '古典主义', '', '交响曲与弦乐四重奏传统的重要奠基者，以机智、结构和形式创新著称。', '海顿长期服务于埃斯特哈齐宫廷，在相对稳定的环境中持续实验。他的音乐把清晰形式与幽默感结合起来，塑造了古典主义器乐语言的骨架。', '["交响曲","弦乐四重奏","幽默","形式创新"]'::jsonb, '[{"year":1761,"event":"进入埃斯特哈齐家族任职。"},{"year":1791,"event":"首次赴伦敦，创作伦敦交响曲。"},{"year":1798,"event":"清唱剧《创世纪》首演。"}]'::jsonb, '["haydn-surprise","haydn-emperor-quartet","haydn-creation"]'::jsonb, '["mozart","beethoven","handel"]'::jsonb, false),
  ('beethoven', 'beethoven', 'Ludwig van Beethoven', '路德维希·范·贝多芬', 1770, 1827, '德国', '古典主义', '', '从古典主义走向浪漫主义的关键人物，把个人意志、冲突和胜利写进交响音乐。', '贝多芬继承海顿与莫扎特的形式传统，却以更强烈的动机发展、戏剧冲突和精神张力扩展了音乐的表达边界。他的作品成为现代音乐会文化的核心。', '["英雄性","动机发展","交响曲","钢琴奏鸣曲"]'::jsonb, '[{"year":1792,"event":"前往维也纳深造并逐渐成名。"},{"year":1804,"event":"完成《第三交响曲“英雄”》。"},{"year":1824,"event":"《第九交响曲》首演。"}]'::jsonb, '["beethoven-symphony-5","beethoven-moonlight","beethoven-symphony-9"]'::jsonb, '["mozart","brahms","schubert"]'::jsonb, true),
  ('schubert', 'schubert', 'Franz Schubert', '弗朗茨·舒伯特', 1797, 1828, '奥地利', '浪漫主义', '', '德奥艺术歌曲的高峰，也在室内乐和交响曲中展开诗意、孤独与远方感。', '舒伯特把诗歌的瞬间情绪转化为旋律、和声与钢琴织体。他的音乐常在亲密空间中显露辽阔风景，是早期浪漫主义最动人的声音之一。', '["艺术歌曲","抒情","转调","室内乐"]'::jsonb, '[{"year":1815,"event":"创作《魔王》等大量歌曲。"},{"year":1822,"event":"写下《未完成交响曲》。"},{"year":1828,"event":"生命最后一年完成多部晚期杰作。"}]'::jsonb, '["schubert-erlkonig","schubert-unfinished","schubert-trout"]'::jsonb, '["beethoven","schumann","brahms"]'::jsonb, false),
  ('chopin', 'chopin', 'Frédéric Chopin', '弗里德里克·肖邦', 1810, 1849, '波兰 / 法国', '浪漫主义', '', '钢琴诗人，以夜曲、玛祖卡、波兰舞曲和练习曲拓展了钢琴的歌唱与色彩。', '肖邦几乎把全部创造力投注于钢琴。他的作品既有沙龙的精微，也有民族记忆和内在戏剧，让钢琴成为最细腻的独白者。', '["钢琴","夜曲","民族舞曲","装饰音"]'::jsonb, '[{"year":1830,"event":"离开华沙，后定居巴黎。"},{"year":1836,"event":"与乔治·桑相识。"},{"year":1842,"event":"创作成熟期多部夜曲与波兰舞曲。"}]'::jsonb, '["chopin-nocturne-op9-2","chopin-ballade-1","chopin-polonaise-heroic"]'::jsonb, '["liszt","schumann","rachmaninoff"]'::jsonb, true),
  ('liszt', 'liszt', 'Franz Liszt', '弗朗茨·李斯特', 1811, 1886, '匈牙利', '浪漫主义', '', '钢琴炫技时代的标志人物，也是交响诗的重要开创者。', '李斯特把钢琴演奏推向前所未有的舞台化高度，同时在魏玛时期发展交响诗理念。他的音乐兼具宗教沉思、文学想象和惊人的技术爆发力。', '["炫技","交响诗","钢琴改编","主题变形"]'::jsonb, '[{"year":1848,"event":"定居魏玛，专注作曲与指挥。"},{"year":1854,"event":"创作《前奏曲》。"},{"year":1865,"event":"在罗马接受小品级圣职。"}]'::jsonb, '["liszt-la-campanella","liszt-liebestraum","liszt-les-preludes"]'::jsonb, '["chopin","wagner","mahler"]'::jsonb, false),
  ('schumann', 'schumann', 'Robert Schumann', '罗伯特·舒曼', 1810, 1856, '德国', '浪漫主义', '', '早期浪漫主义的文学化声音，以钢琴套曲、艺术歌曲和内心角色塑造见长。', '舒曼的音乐像一组心理速写，常在热情与沉思、幻想与碎片之间切换。他也以评论家身份支持肖邦、勃拉姆斯等同代作曲家。', '["幻想","文学性","钢琴套曲","艺术歌曲"]'::jsonb, '[{"year":1834,"event":"创办《新音乐杂志》。"},{"year":1840,"event":"与克拉拉结婚并创作大量歌曲。"},{"year":1853,"event":"发表文章《新的道路》推介勃拉姆斯。"}]'::jsonb, '["schumann-traumerei","schumann-piano-concerto","schumann-dichterliebe"]'::jsonb, '["chopin","brahms","schubert"]'::jsonb, false),
  ('mendelssohn', 'mendelssohn', 'Felix Mendelssohn', '费利克斯·门德尔松', 1809, 1847, '德国', '浪漫主义', '', '兼具古典清澈与浪漫诗意的作曲家，也推动了巴赫音乐的复兴。', '门德尔松以明亮、流动、结构精巧的音乐著称。他在莱比锡的活动对十九世纪音乐生活影响深远，并通过指挥《马太受难曲》让巴赫重新回到公众视野。', '["清澈","序曲","轻盈","巴赫复兴"]'::jsonb, '[{"year":1826,"event":"创作《仲夏夜之梦》序曲。"},{"year":1829,"event":"指挥巴赫《马太受难曲》。"},{"year":1843,"event":"创办莱比锡音乐学院。"}]'::jsonb, '["mendelssohn-hebrides","mendelssohn-violin-concerto","mendelssohn-songs-without-words"]'::jsonb, '["bach","schumann","brahms"]'::jsonb, false),
  ('brahms', 'brahms', 'Johannes Brahms', '约翰内斯·勃拉姆斯', 1833, 1897, '德国', '浪漫主义', '', '把古典结构与浪漫情感压缩在厚重织体中的德奥传统继承者。', '勃拉姆斯在贝多芬阴影下写作，却发展出独特的内敛力量。他的交响曲、协奏曲和室内乐常以严密发展承载深沉温度。', '["古典结构","厚重织体","室内乐","变奏"]'::jsonb, '[{"year":1853,"event":"结识舒曼夫妇并获得推介。"},{"year":1876,"event":"《第一交响曲》首演。"},{"year":1887,"event":"创作《双重协奏曲》。"}]'::jsonb, '["brahms-symphony-1","brahms-hungarian-dance-5","brahms-violin-concerto"]'::jsonb, '["beethoven","schumann","dvorak"]'::jsonb, true),
  ('tchaikovsky', 'tchaikovsky', 'Pyotr Ilyich Tchaikovsky', '彼得·伊里奇·柴可夫斯基', 1840, 1893, '俄罗斯', '浪漫主义', '', '旋律极富感染力的俄罗斯浪漫主义作曲家，芭蕾、交响曲和协奏曲广受欢迎。', '柴可夫斯基把西欧形式与俄罗斯旋律感结合起来。他的音乐情绪直接、戏剧性强，既适合舞台，也在交响结构中展现命运般的张力。', '["旋律","芭蕾","命运动机","戏剧性"]'::jsonb, '[{"year":1877,"event":"创作《第四交响曲》与《天鹅湖》相关作品。"},{"year":1880,"event":"完成《1812序曲》。"},{"year":1893,"event":"《第六交响曲“悲怆”》首演。"}]'::jsonb, '["tchaikovsky-swan-lake","tchaikovsky-piano-concerto-1","tchaikovsky-pathetique"]'::jsonb, '["dvorak","rachmaninoff","prokofiev"]'::jsonb, true),
  ('dvorak', 'dvorak', 'Antonín Dvořák', '安东宁·德沃夏克', 1841, 1904, '捷克', '民族乐派', '', '将捷克民间气质、德奥结构和新大陆想象融为一体的民族乐派代表。', '德沃夏克的音乐自然、开阔、旋律亲切。他在布拉格与纽约之间建立了民族风格与国际音乐语言的桥梁。', '["民族风格","旋律","交响曲","大提琴"]'::jsonb, '[{"year":1878,"event":"《斯拉夫舞曲》带来国际声誉。"},{"year":1892,"event":"赴纽约任国家音乐学院院长。"},{"year":1893,"event":"完成《新世界交响曲》。"}]'::jsonb, '["dvorak-new-world","dvorak-cello-concerto","dvorak-slavonic-dance"]'::jsonb, '["brahms","tchaikovsky","smetana"]'::jsonb, false),
  ('mahler', 'mahler', 'Gustav Mahler', '古斯塔夫·马勒', 1860, 1911, '奥地利', '浪漫主义', '', '晚期浪漫主义交响世界的拓展者，把歌曲、自然、葬礼和宇宙感纳入巨型结构。', '马勒既是重要指挥家，也是将交响曲推向哲学化、剧场化和自传化的作曲家。他的音乐常在民间旋律、讽刺、狂喜与崩塌之间切换。', '["巨型交响曲","歌曲性","讽刺","宇宙感"]'::jsonb, '[{"year":1888,"event":"完成《第一交响曲》初稿。"},{"year":1897,"event":"任维也纳宫廷歌剧院总监。"},{"year":1908,"event":"《第八交响曲》首演。"}]'::jsonb, '["mahler-symphony-1","mahler-adagietto","mahler-resurrection"]'::jsonb, '["brahms","tchaikovsky","shostakovich"]'::jsonb, false),
  ('debussy', 'debussy', 'Claude Debussy', '克洛德·德彪西', 1862, 1918, '法国', '印象主义', '', '以色彩、和声和流动结构改变了二十世纪音乐听觉的法国作曲家。', '德彪西不喜欢被简单称为印象主义者，但他的音乐确实像光影、水面和气味一样变化。他弱化传统功能和声，打开了音色与时间的新空间。', '["音色","全音阶","水与光","模糊调性"]'::jsonb, '[{"year":1894,"event":"《牧神午后前奏曲》首演。"},{"year":1905,"event":"完成《大海》。"},{"year":1910,"event":"创作钢琴前奏曲集。"}]'::jsonb, '["debussy-clair-de-lune","debussy-la-mer","debussy-faun"]'::jsonb, '["ravel","stravinsky","chopin"]'::jsonb, true),
  ('ravel', 'ravel', 'Maurice Ravel', '莫里斯·拉威尔', 1875, 1937, '法国', '印象主义', '', '精密、冷静而绚丽的法国作曲家，以管弦乐配器和舞蹈节奏著称。', '拉威尔的音乐像精工制作的机械珠宝：轮廓清晰、色彩耀眼、节奏敏锐。他既延续法国音色传统，也吸收西班牙、爵士和舞蹈元素。', '["配器","舞蹈","精密","西班牙色彩"]'::jsonb, '[{"year":1908,"event":"创作《夜之幽灵》。"},{"year":1928,"event":"完成《波莱罗》。"},{"year":1930,"event":"创作《左手钢琴协奏曲》。"}]'::jsonb, '["ravel-bolero","ravel-daphnis","ravel-pavane"]'::jsonb, '["debussy","stravinsky","prokofiev"]'::jsonb, false),
  ('stravinsky', 'stravinsky', 'Igor Stravinsky', '伊戈尔·斯特拉文斯基', 1882, 1971, '俄罗斯 / 法国 / 美国', '现代主义', '', '二十世纪音乐变革的核心人物，从原始主义、 neoclassicism 到序列技法不断转向。', '斯特拉文斯基用节奏、重音和块状音响重塑了现代音乐。他的芭蕾作品震动巴黎，也在后半生持续以清醒、克制的方式重写传统。', '["节奏","芭蕾","新古典","现代主义"]'::jsonb, '[{"year":1910,"event":"《火鸟》在巴黎首演。"},{"year":1913,"event":"《春之祭》首演引发轰动。"},{"year":1920,"event":"进入新古典主义创作阶段。"}]'::jsonb, '["stravinsky-rite","stravinsky-firebird","stravinsky-pulcinella"]'::jsonb, '["debussy","ravel","prokofiev"]'::jsonb, false),
  ('rachmaninoff', 'rachmaninoff', 'Sergei Rachmaninoff', '谢尔盖·拉赫玛尼诺夫', 1873, 1943, '俄罗斯 / 美国', '浪漫主义', '', '晚期浪漫主义钢琴传统的代表，以宽广旋律、钟声和浓烈和声闻名。', '拉赫玛尼诺夫在现代主义兴起时坚持浪漫主义语言，却以高度个人化的旋律和钢琴织体赢得持久热爱。他也是二十世纪最重要的钢琴家之一。', '["钢琴","宽广旋律","钟声","晚期浪漫"]'::jsonb, '[{"year":1901,"event":"《第二钢琴协奏曲》首演成功。"},{"year":1917,"event":"离开俄罗斯。"},{"year":1934,"event":"创作《帕格尼尼主题狂想曲》。"}]'::jsonb, '["rachmaninoff-piano-concerto-2","rachmaninoff-vocalise","rachmaninoff-paganini"]'::jsonb, '["tchaikovsky","chopin","prokofiev"]'::jsonb, false),
  ('prokofiev', 'prokofiev', 'Sergei Prokofiev', '谢尔盖·普罗科菲耶夫', 1891, 1953, '俄罗斯 / 苏联', '现代主义', '', '兼具尖锐节奏、讽刺感、抒情旋律和舞台想象力的二十世纪作曲家。', '普罗科菲耶夫的音乐常带有钢铁般的节奏和机智的反讽，但也能写出令人难忘的抒情旋律。他在钢琴、芭蕾、歌剧和电影音乐中都留下代表作。', '["节奏","讽刺","芭蕾","现代钢琴"]'::jsonb, '[{"year":1917,"event":"创作《第一交响曲“古典”》。"},{"year":1936,"event":"定居苏联并完成《罗密欧与朱丽叶》。"},{"year":1945,"event":"《第五交响曲》首演。"}]'::jsonb, '["prokofiev-classical-symphony","prokofiev-romeo","prokofiev-piano-concerto-3"]'::jsonb, '["stravinsky","shostakovich","rachmaninoff"]'::jsonb, false),
  ('shostakovich', 'shostakovich', 'Dmitri Shostakovich', '德米特里·肖斯塔科维奇', 1906, 1975, '苏联', '现代主义', '', '二十世纪交响曲与弦乐四重奏的重要声音，音乐中充满讽刺、压迫和隐秘独白。', '肖斯塔科维奇在复杂政治环境中写作。他的音乐表面可能是进行曲、舞曲或官方庆典，内部却常有尖锐讽刺、孤独和恐惧。', '["讽刺","交响曲","四重奏","政治阴影"]'::jsonb, '[{"year":1936,"event":"歌剧《姆岑斯克县的麦克白夫人》遭批判。"},{"year":1937,"event":"《第五交响曲》首演。"},{"year":1960,"event":"完成《第八弦乐四重奏》。"}]'::jsonb, '["shostakovich-symphony-5","shostakovich-string-quartet-8","shostakovich-waltz-2"]'::jsonb, '["prokofiev","mahler","stravinsky"]'::jsonb, false)
insert into public.works (id, slug, composer_id, title, title_cn, year, genre, period, description, movements, listening_links, featured) values
  ('bach-cello-suite-1', 'bach-cello-suite-1', 'bach', 'Cello Suite No. 1 in G major', 'G大调第一无伴奏大提琴组曲', 1720, '组曲', '巴洛克', '开篇前奏曲以分解和弦展开，像一座由单线条建成的拱顶，是进入巴赫器乐世界最亲切的入口。', '["Prelude","Allemande","Courante","Sarabande","Menuet I/II","Gigue"]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Bach%20Cello%20Suite%20No.%201"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Bach%20Cello%20Suite%20No.%201"}]'::jsonb, true),
