  ('dvorak-cello-concerto', 'dvorak-cello-concerto', 'dvorak', 'Cello Concerto in B minor', 'b小调大提琴协奏曲', 1895, '协奏曲', '民族乐派', '大提琴以罕见的交响性和歌唱性展开，是该体裁最高峰之一。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Dvorak%20Cello%20Concerto"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Dvorak%20Cello%20Concerto"}]'::jsonb, false),
  ('dvorak-slavonic-dance', 'dvorak-slavonic-dance-op46-8', 'dvorak', 'Slavonic Dance Op. 46 No. 8', '斯拉夫舞曲 Op.46 No.8', 1878, '舞曲', '民族乐派', '民间舞蹈节奏与明亮配器结合，展现德沃夏克亲切而热烈的民族风格。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Dvorak%20Slavonic%20Dance%20Op.46%20No.8"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Dvorak%20Slavonic%20Dance%20Op.46%20No.8"}]'::jsonb, false),
  ('mahler-symphony-1', 'mahler-symphony-1', 'mahler', 'Symphony No. 1 Titan', '第一交响曲“巨人”', 1888, '交响曲', '浪漫主义', '从自然苏醒到葬礼进行曲和终曲爆发，马勒的交响宇宙由此展开。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Mahler%20Symphony%20No.%201%20Titan"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Mahler%20Symphony%20No.%201%20Titan"}]'::jsonb, false),
  ('mahler-adagietto', 'mahler-adagietto', 'mahler', 'Adagietto from Symphony No. 5', '第五交响曲小柔板', 1902, '交响曲乐章', '浪漫主义', '弦乐与竖琴构成近乎无声的情书，是马勒最柔软的片段之一。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Mahler%20Adagietto"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Mahler%20Adagietto"}]'::jsonb, false),
  ('mahler-resurrection', 'mahler-symphony-2-resurrection', 'mahler', 'Symphony No. 2 Resurrection', '第二交响曲“复活”', 1894, '交响曲', '浪漫主义', '从死亡追问走向合唱的复活宣告，规模宏大而精神张力强烈。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Mahler%20Symphony%20No.%202%20Resurrection"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Mahler%20Symphony%20No.%202%20Resurrection"}]'::jsonb, false),
  ('debussy-clair-de-lune', 'debussy-clair-de-lune', 'debussy', 'Clair de lune', '月光', 1905, '钢琴小品', '印象主义', '柔和和声与流动节奏营造月色般的朦胧，是德彪西最受欢迎的钢琴作品。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Debussy%20Clair%20de%20lune"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Debussy%20Clair%20de%20lune"}]'::jsonb, true),
  ('debussy-la-mer', 'debussy-la-mer', 'debussy', 'La Mer', '大海', 1905, '管弦乐', '印象主义', '不是描摹海浪，而是让光、风和水的运动成为管弦乐结构。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Debussy%20La%20Mer"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Debussy%20La%20Mer"}]'::jsonb, false),
  ('debussy-faun', 'debussy-faun', 'debussy', 'Prélude à l''après-midi d''un faune', '牧神午后前奏曲', 1894, '管弦乐前奏曲', '印象主义', '长笛开头像午后梦境的第一缕热气，常被视为现代音乐的开端之一。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Debussy%20Prelude%20to%20the%20Afternoon%20of%20a%20Faun"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Debussy%20Prelude%20to%20the%20Afternoon%20of%20a%20Faun"}]'::jsonb, false),
  ('ravel-bolero', 'ravel-bolero', 'ravel', 'Boléro', '波莱罗', 1928, '管弦乐', '印象主义', '单一节奏和主题不断重复，通过配器和力度累积形成不可阻挡的推进。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Ravel%20Bolero"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Ravel%20Bolero"}]'::jsonb, false),
  ('ravel-daphnis', 'ravel-daphnis-et-chloe', 'ravel', 'Daphnis et Chloé', '达夫尼与克洛埃', 1912, '芭蕾', '印象主义', '绚丽管弦乐和合唱色彩构成拉威尔最奢华的音响画卷。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Ravel%20Daphnis%20et%20Chloe"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Ravel%20Daphnis%20et%20Chloe"}]'::jsonb, false),
  ('ravel-pavane', 'ravel-pavane', 'ravel', 'Pavane pour une infante défunte', '悼念公主的帕凡舞曲', 1899, '钢琴 / 管弦乐', '印象主义', '古老舞曲节奏与优雅哀愁结合，像一幅褪色宫廷画像。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Ravel%20Pavane%20for%20a%20Dead%20Princess"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Ravel%20Pavane%20for%20a%20Dead%20Princess"}]'::jsonb, false),
  ('stravinsky-rite', 'stravinsky-rite-of-spring', 'stravinsky', 'The Rite of Spring', '春之祭', 1913, '芭蕾', '现代主义', '强烈节奏、不规则重音和原始祭祀想象震动了二十世纪音乐。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Stravinsky%20The%20Rite%20of%20Spring"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Stravinsky%20The%20Rite%20of%20Spring"}]'::jsonb, true),
  ('stravinsky-firebird', 'stravinsky-firebird', 'stravinsky', 'The Firebird', '火鸟', 1910, '芭蕾', '现代主义', '俄罗斯童话、绚丽配器和戏剧推进结合，使斯特拉文斯基一举成名。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Stravinsky%20Firebird"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Stravinsky%20Firebird"}]'::jsonb, false),
  ('stravinsky-pulcinella', 'stravinsky-pulcinella', 'stravinsky', 'Pulcinella', '普钦奈拉', 1920, '芭蕾组曲', '现代主义', '以十八世纪材料为起点，开启斯特拉文斯基的新古典主义阶段。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Stravinsky%20Pulcinella"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Stravinsky%20Pulcinella"}]'::jsonb, false),
  ('rachmaninoff-piano-concerto-2', 'rachmaninoff-piano-concerto-2', 'rachmaninoff', 'Piano Concerto No. 2', '第二钢琴协奏曲', 1901, '协奏曲', '浪漫主义', '钟声般开头后展开宽广旋律，是晚期浪漫主义钢琴协奏曲的代表。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Rachmaninoff%20Piano%20Concerto%20No.%202"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Rachmaninoff%20Piano%20Concerto%20No.%202"}]'::jsonb, false),
  ('rachmaninoff-vocalise', 'rachmaninoff-vocalise', 'rachmaninoff', 'Vocalise', '练声曲', 1915, '声乐 / 器乐改编', '浪漫主义', '无词旋律像长长的叹息，被改编为各种乐器版本。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Rachmaninoff%20Vocalise"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Rachmaninoff%20Vocalise"}]'::jsonb, false),
  ('rachmaninoff-paganini', 'rachmaninoff-paganini-rhapsody', 'rachmaninoff', 'Rhapsody on a Theme of Paganini', '帕格尼尼主题狂想曲', 1934, '钢琴与乐队', '浪漫主义', '第十八变奏以倒影般的旋律成为二十世纪最动人的浪漫时刻之一。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Rachmaninoff%20Rhapsody%20on%20a%20Theme%20of%20Paganini"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Rachmaninoff%20Rhapsody%20on%20a%20Theme%20of%20Paganini"}]'::jsonb, false),
  ('prokofiev-classical-symphony', 'prokofiev-classical-symphony', 'prokofiev', 'Symphony No. 1 Classical', '第一交响曲“古典”', 1917, '交响曲', '现代主义', '以海顿式透明形式写出现代机智，短小、明亮而锋利。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Prokofiev%20Classical%20Symphony"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Prokofiev%20Classical%20Symphony"}]'::jsonb, false),
  ('prokofiev-romeo', 'prokofiev-romeo-and-juliet', 'prokofiev', 'Romeo and Juliet', '罗密欧与朱丽叶', 1936, '芭蕾', '现代主义', '尖锐节奏与动人爱情主题并存，《骑士之舞》尤其具有压迫感。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Prokofiev%20Romeo%20and%20Juliet"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Prokofiev%20Romeo%20and%20Juliet"}]'::jsonb, false),
  ('prokofiev-piano-concerto-3', 'prokofiev-piano-concerto-3', 'prokofiev', 'Piano Concerto No. 3', '第三钢琴协奏曲', 1921, '协奏曲', '现代主义', '钢琴像打击乐与歌唱者的混合体，闪烁、犀利而富有舞台感。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Prokofiev%20Piano%20Concerto%20No.%203"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Prokofiev%20Piano%20Concerto%20No.%203"}]'::jsonb, false),
  ('shostakovich-symphony-5', 'shostakovich-symphony-5', 'shostakovich', 'Symphony No. 5', '第五交响曲', 1937, '交响曲', '现代主义', '表面胜利的终曲之下潜藏紧张与苦涩，是二十世纪交响曲中最复杂的文本之一。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Shostakovich%20Symphony%20No.%205"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Shostakovich%20Symphony%20No.%205"}]'::jsonb, false),
  ('shostakovich-string-quartet-8', 'shostakovich-string-quartet-8', 'shostakovich', 'String Quartet No. 8', '第八弦乐四重奏', 1960, '弦乐四重奏', '现代主义', '以作曲家姓名动机构成近乎自传式的独白，短促而灼人。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Shostakovich%20String%20Quartet%20No.%208"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Shostakovich%20String%20Quartet%20No.%208"}]'::jsonb, false),
  ('shostakovich-waltz-2', 'shostakovich-waltz-2', 'shostakovich', 'Waltz No. 2', '第二圆舞曲', 1956, '管弦乐小品', '现代主义', '旋律优雅却带着淡淡疏离感，像一场明亮灯光下的苦笑。', '[]'::jsonb, '[{"platform":"YouTube 搜索","url":"https://www.youtube.com/results?search_query=Shostakovich%20Waltz%20No.%202"},{"platform":"Apple Music 搜索","url":"https://music.apple.com/search?term=Shostakovich%20Waltz%20No.%202"}]'::jsonb, false)
