insert into public.articles (id, slug, title, excerpt, cover_url, category, published_at, content, related_composer_ids, related_work_ids) values
  ('article-beethoven-start', 'start-with-beethoven', '第一次听贝多芬，从哪几首开始', '如果只知道《命运》，这条路线会带你从戏剧动机、钢琴独白一路走到《欢乐颂》。', '', '古典音乐入门', '2026-06-08', '贝多芬适合从“冲突”开始听。《第五交响曲》的四音动机像敲门声一样进入音乐史，它让你立刻理解贝多芬如何用最小材料建起巨大戏剧。
